"use strict";(self.webpackChunkwebsite=self.webpackChunkwebsite||[]).push([[19837],{28453:(e,t,a)=>{a.d(t,{R:()=>o,x:()=>s});var r=a(96540);const n={},i=r.createContext(n);function o(e){const t=r.useContext(i);return r.useMemo((function(){return"function"==typeof e?e(t):{...t,...e}}),[t,e])}function s(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(n):e.components||n:o(e.components),r.createElement(i.Provider,{value:t},e.children)}},96347:(e,t,a)=>{a.r(t),a.d(t,{assets:()=>l,contentTitle:()=>s,default:()=>h,frontMatter:()=>o,metadata:()=>r,toc:()=>c});const r=JSON.parse('{"id":"Preface End facism/eos/EO_14299_Dl_Security_gpt-5_4_20260307_005056","title":"EO 14299 Deploying Advanced Nuclear Reactor Technologies for National Security","description":"Table of Contents","source":"@site/docs/1. Preface End facism/eos/EO_14299_Dl_Security_gpt-5_4_20260307_005056.md","sourceDirName":"1. Preface End facism/eos","slug":"/Preface End facism/eos/EO_14299_Dl_Security_gpt-5_4_20260307_005056","permalink":"/firstpub-Platform/docs/Preface End facism/eos/EO_14299_Dl_Security_gpt-5_4_20260307_005056","draft":false,"unlisted":false,"editUrl":"https://github.com/unitedprogressparty/firstpub-Platform/tree/main/docs/1. Preface End facism/eos/EO_14299_Dl_Security_gpt-5_4_20260307_005056.md","tags":[],"version":"current","frontMatter":{"title":"EO 14299 Deploying Advanced Nuclear Reactor Technologies for National Security"},"sidebar":"tutorialSidebar","previous":{"title":"EO 14239 Achieving Efficiency Through State and Local Preparedness","permalink":"/firstpub-Platform/docs/Preface End facism/eos/EO_14239_Aeparedness_gpt-5-mini_20260307_130516"},"next":{"title":"EO 14305 Restoring American Airspace Sovereignty","permalink":"/firstpub-Platform/docs/Preface End facism/eos/EO_14305_Rovereignty_gpt-5-mini_20260307_111303"}}');var n=a(74848),i=a(28453);const o={title:"EO 14299 Deploying Advanced Nuclear Reactor Technologies for National Security"},s="EO 14299: Deploying Advanced Nuclear Reactor Technologies for National Security",l={},c=[{value:"Table of Contents",id:"table-of-contents",level:2},{value:"Executive Summary",id:"executive-summary",level:2},{value:"What the Order Formally Says",id:"what-the-order-formally-says",level:2},{value:"What the Order Really Does",id:"what-the-order-really-does",level:2},{value:"How the Order Has Already Been Put to Work",id:"how-the-order-has-already-been-put-to-work",level:2},{value:"Who Benefits and Who Pays",id:"who-benefits-and-who-pays",level:2},{value:"Who the Administration Is Trying to Hurt",id:"who-the-administration-is-trying-to-hurt",level:2},{value:"Legal Authority, Constitutional Stakes, and Litigation Exposure",id:"legal-authority-constitutional-stakes-and-litigation-exposure",level:2},{value:"Implementation Feasibility and Agency Capacity",id:"implementation-feasibility-and-agency-capacity",level:2},{value:"Fiscal and Economic Effects",id:"fiscal-and-economic-effects",level:2},{value:"Institutional, Regulatory, and Societal Harms",id:"institutional-regulatory-and-societal-harms",level:2},{value:"Corruption, Patronage, and Self-Dealing Risk",id:"corruption-patronage-and-self-dealing-risk",level:2},{value:"How a Later Administration Could Reverse, Mitigate, or Reform It",id:"how-a-later-administration-could-reverse-mitigate-or-reform-it",level:2},{value:"Conclusion",id:"conclusion",level:2}];function d(e){const t={a:"a",h1:"h1",h2:"h2",header:"header",p:"p",...(0,i.R)(),...e.components};return(0,n.jsxs)(n.Fragment,{children:[(0,n.jsx)(t.header,{children:(0,n.jsx)(t.h1,{id:"eo-14299-deploying-advanced-nuclear-reactor-technologies-for-national-security",children:"EO 14299: Deploying Advanced Nuclear Reactor Technologies for National Security"})}),"\n",(0,n.jsx)(t.h2,{id:"table-of-contents",children:"Table of Contents"}),"\n",(0,n.jsxs)(t.p,{children:["This report moves from the text of Executive Order 14299 itself, to the machinery it creates, to the way that machinery has already been put to work, to the people and institutions it advantages and injures, to its legal and constitutional weak points, to its fiscal and economic effects, to the concrete harms and corruption risks embedded in its design, and finally to the ways a later administration could unwind or structurally reform it. (",(0,n.jsx)(t.a,{href:"https://www.federalregister.gov/documents/full_text/html/2025/05/29/2025-09796.html",children:"federalregister.gov"}),")"]}),"\n",(0,n.jsx)(t.h2,{id:"executive-summary",children:"Executive Summary"}),"\n",(0,n.jsxs)(t.p,{children:["Executive Order 14299, signed on May 23, 2025, is not just a nuclear policy document. It is a power-transfer document. Formally, it orders the rapid deployment of advanced reactors on military installations and DOE sites, directs DOE to treat certain AI data centers connected to DOE facilities as \u201ccritical defense facilities,\u201d requires DOE to use \u201call available legal authorities\u201d to authorize privately funded reactors on federal land, orders release of at least 20 metric tons of HALEU for qualifying private projects, pushes fuel recycling and reprocessing at federal sites, compresses export approvals, prioritizes security clearances, and tells Defense and Energy to look for ways to use categorical exclusions, emergency procedures, and other shortcuts under NEPA. (",(0,n.jsx)(t.a,{href:"https://www.federalregister.gov/documents/full_text/html/2025/05/29/2025-09796.html",children:"federalregister.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["The order\u2019s real function is to move scarce public assets and public-law privileges toward a preferred coalition of military agencies, AI developers, reactor vendors, exporters, and federal-site landlords while weakening the institutions designed to slow dangerous or politically connected projects down. The White House sells that move as \u201cnational security,\u201d but the policy architecture shows something more familiar and more corrosive: privatization of public land and fuel, militarization of civilian energy siting, and procedural compression aimed at neutralizing environmental review, independent regulation, and community resistance. The administration is not trying to solve a narrowly defined defense emergency. It is trying to build a fast lane around ordinary democratic checks. (",(0,n.jsx)(t.a,{href:"https://www.federalregister.gov/documents/full_text/html/2025/05/29/2025-09796.html",children:"federalregister.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["The downstream record already points in that direction. DOE selected Idaho National Laboratory, Oak Ridge Reservation, the Paducah Gaseous Diffusion Plant, and Savannah River Site for AI data center and energy projects on July 24, 2025; DOE then issued site solicitations at Idaho and Oak Ridge for long-term leasing arrangements funded by private applicants; the Army launched the Janus Program in October 2025 and, by November 2025, had selected nine installations for possible microreactor siting while using DIU\u2019s Other Transaction and Commercial Solutions Opening tools; and on February 2, 2026 DOE created a new categorical exclusion covering authorization, siting, construction, operation, and decommissioning of advanced reactors. That is not a frozen text. It is an active campaign to operationalize the order\u2019s deregulatory core. (",(0,n.jsx)(t.a,{href:"https://www.energy.gov/articles/doe-announces-site-selection-ai-data-center-and-energy-infrastructure-development-federal?utm_source=openai",children:"energy.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["The administration is trying to hurt the institutions and constituencies that can say no. The immediate targets are independent nuclear oversight, environmental review, tribal and community leverage, and congressional control over how public resources are allocated. The collateral targets are the communities around contaminated DOE sites and military bases that are expected to absorb new hazard, new secrecy, and new land-use burdens in exchange for promises of \u201cdominance\u201d and \u201cinnovation.\u201d The order is durable only to the extent later administrations allow its implementing decisions to harden into contracts, leases, fuel allocations, and site-specific determinations. Much of it can be reversed by executive action, but some of the damage becomes harder to unwind once land is leased, OT agreements are signed, reactors are partly built, or export-finance pipelines are underway. (",(0,n.jsx)(t.a,{href:"https://www.energy.gov/sites/default/files/2025-04/RFI%20to%20Inform%20Public%20Bids%20to%20Construct%20AI%20Infrastructure%20%28website%20copy%29%20-%202025.04.10.pdf",children:"energy.gov"}),")"]}),"\n",(0,n.jsx)(t.h2,{id:"what-the-order-formally-says",children:"What the Order Formally Says"}),"\n",(0,n.jsxs)(t.p,{children:["The order\u2019s formal text has eleven sections, but its substance sits in Sections 3 through 9. Section 3 orders the Secretary of Defense, through the Secretary of the Army, to establish a \u201cprogram of record\u201d for nuclear energy for both installation and operational energy and to commence operation of an Army-regulated reactor at a domestic military installation no later than September 30, 2028. Section 4 turns to DOE and directs the Secretary of Energy to initiate designation of certain AI data centers associated with DOE facilities as \u201ccritical defense facilities,\u201d to designate DOE-controlled sites for advanced reactors within 90 days, and to use all available legal authorities to site and authorize privately funded advanced reactors at DOE sites with a goal of first operation within 30 months of the order. (",(0,n.jsx)(t.a,{href:"https://www.federalregister.gov/documents/full_text/html/2025/05/29/2025-09796.html",children:"federalregister.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["Section 5 is where the public subsidy becomes unmistakable. DOE must identify useful uranium and plutonium in its inventories, release at least 20 metric tons of HALEU into a readily available fuel bank for qualifying private-sector projects authorized at DOE sites, and pursue domestic fuel-fabrication and supply chains. The same section directs Defense and Energy to use all available legal authorities to authorize privately funded recycling, reprocessing, and fuel-fabrication technologies at federal sites for national-security, commercial, and research-reactor fuel. Section 6 authorizes Defense and Energy to execute \u201cany useful contract or agreement\u201d to implement the order. (",(0,n.jsx)(t.a,{href:"https://www.federalregister.gov/documents/full_text/html/2025/05/29/2025-09796.html",children:"federalregister.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["Section 7 is the order\u2019s bluntest signal about oversight. Defense and Energy are told to consult CEQ about applying existing categorical exclusions, adopting other agencies\u2019 categorical exclusions, creating new categorical exclusions, using other agencies\u2019 emergency and permitting procedures, and developing alternative NEPA arrangements for emergencies. Section 8 then shifts outward, directing a campaign for nuclear exports through at least 20 new section 123 agreements by the close of the 120th Congress, a 30-day target for technology-transfer export authorization decisions once applications and required analysis are complete, and strategies using DFC, USTDA, EXIM, and multilateral development banks to finance and advocate for U.S. nuclear exports. Section 9 prioritizes DOE and DoD security clearances for nuclear and fuel-cycle technologies. (",(0,n.jsx)(t.a,{href:"https://www.federalregister.gov/documents/full_text/html/2025/05/29/2025-09796.html",children:"federalregister.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["The order contains the usual caveats that it must be implemented consistent with applicable law, subject to appropriations, OMB procurement processes, and nonproliferation obligations. Those clauses matter, but they do not cancel the order\u2019s intent. They merely acknowledge that executive ambition still runs into statutes, budgets, and courts. The real question is not whether the order claims fidelity to law. Every aggressive executive order does. The real question is how much law the administration can bend before someone stops it. (",(0,n.jsx)(t.a,{href:"https://www.federalregister.gov/documents/full_text/html/2025/05/29/2025-09796.html",children:"federalregister.gov"}),")"]}),"\n",(0,n.jsx)(t.h2,{id:"what-the-order-really-does",children:"What the Order Really Does"}),"\n",(0,n.jsxs)(t.p,{children:["In practice, EO 14299 fuses three projects that should have been kept more separate: military energy resilience, commercial advanced-reactor deployment, and AI infrastructure expansion. By treating AI data centers at or coordinated with DOE facilities as potential \u201ccritical defense facilities,\u201d the order effectively wraps private compute demand in national-security language. That move is not semantic fluff. It gives the administration a rationale to elevate favored projects above normal public-interest balancing and to frame dissent as obstruction of defense preparedness rather than disagreement about land use, risk, subsidies, or local priorities. (",(0,n.jsx)(t.a,{href:"https://www.whitehouse.gov/presidential-actions/2025/05/deploying-advanced-nuclear-reactor-technologies-for-national-security/",children:"whitehouse.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["The order also works as an asset-transfer device. Federal land, DOE technical infrastructure, excess nuclear materials, licensing attention, diplomatic bandwidth, export-finance tools, and high-level security processing are all marshaled toward private reactor and AI projects. DOE\u2019s early AI-infrastructure RFI made that orientation explicit by asking about leasing DOE land, co-locating data centers with new generation, and operating, maintaining, and decommissioning infrastructure on federal land. It also acknowledged foreseeable concerns about tribal resources, water use, noise, energy prices, land footprint, and local communities. The order\u2019s answer to those concerns is not robust consent. It is speed. (",(0,n.jsx)(t.a,{href:"https://www.energy.gov/sites/default/files/2025-04/RFI%20to%20Inform%20Public%20Bids%20to%20Construct%20AI%20Infrastructure%20%28website%20copy%29%20-%202025.04.10.pdf",children:"energy.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["Most importantly, the order is part of a larger campaign to weaken the distinction between independent civilian nuclear regulation and executive-branch promotion of nuclear deployment. Congress created the NRC as an independent agency to regulate civilian nuclear uses, while the Energy Reorganization Act left defense nuclear facilities outside NRC regulation. EO 14299 exploits that boundary by pulling reactors serving military installations and DOE-site projects deeper into Defense and DOE-controlled channels, while a companion order, \u201cOrdering the Reform of the Nuclear Regulatory Commission,\u201d pressures the NRC to become a facilitator of deployment rather than a regulator whose first duty is to slow or stop unsafe or ill-conceived projects. (",(0,n.jsx)(t.a,{href:"https://www.nrc.gov/about-nrc/governing-laws.html?utm_source=openai",children:"nrc.gov"}),")"]}),"\n",(0,n.jsx)(t.h2,{id:"how-the-order-has-already-been-put-to-work",children:"How the Order Has Already Been Put to Work"}),"\n",(0,n.jsxs)(t.p,{children:["The most direct implementation came from DOE. On July 24, 2025, DOE announced that four sites, Idaho National Laboratory, Oak Ridge Reservation, Paducah Gaseous Diffusion Plant, and Savannah River Site, would move forward for AI data center and energy-generation development on federal land, and DOE expressly tied that move to EO 14299 as well as the administration\u2019s broader AI and energy orders. That was the moment the order stopped being theoretical and became a land-development pipeline. (",(0,n.jsx)(t.a,{href:"https://www.energy.gov/articles/doe-announces-site-selection-ai-data-center-and-energy-infrastructure-development-federal?utm_source=openai",children:"energy.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["DOE then moved into solicitations. On September 8, 2025, DOE issued a Request for Application for AI data centers and energy projects at Idaho National Laboratory, describing one or more long-term leasing arrangements that would be solely funded by private applicants on roughly 44,000 acres and explicitly prioritizing projects that pair AI data centers with generation and storage, including advanced reactors. On September 30, 2025, DOE issued a similar solicitation for Oak Ridge, again seeking long-term leasing arrangements with private companies responsible for construction, operation, decommissioning, interconnection, permitting, and regulatory compliance. This is exactly how a public land and public mission complex becomes a platform for private compute and private energy deals. (",(0,n.jsx)(t.a,{href:"https://www.energy.gov/ne/articles/energy-department-seeks-proposals-ai-data-centers-energy-projects-idaho-national?utm_source=openai",children:"energy.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["The military side moved as well. The Army formally launched the Janus Program on October 14, 2025, explicitly citing EO 14299 and stating that the Army would use its own nuclear regulatory authorities, in partnership with DOE, to deliver commercial microreactors under a milestone-based model modeled on NASA\u2019s COTS approach. On November 18, 2025, the Army announced the next step: nine installations were selected for possible siting, and the program would use DIU\u2019s Commercial Solutions Opening and Other Transaction Authority processes to solicit and award work. Those choices matter because OT structures are faster and often less transparent than conventional procurement, and because the Army\u2019s own description frames speed and \u201cbending metal\u201d as the goal. (",(0,n.jsx)(t.a,{href:"https://www.army.mil/article/288903/army_announces_janus_program_for_next_generation_nuclear_energy",children:"army.mil"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["The order\u2019s anti-oversight element has also been concretized. On February 2, 2026, DOE established a new categorical exclusion, B5.26, for authorization, siting, construction, operation, reauthorization, and decommissioning of advanced nuclear reactors, while expressly citing EO 14299 as one of the drivers for that step. DOE says application of the exclusion still requires review of integral elements and extraordinary circumstances, but the change nonetheless widens the pathway for projects to avoid an environmental assessment or environmental impact statement. That is a direct institutional effect of the order: less front-end scrutiny, less public process, and more agency discretion. (",(0,n.jsx)(t.a,{href:"https://www.energy.gov/nepa/articles/notice-new-categorical-exclusion-advanced-nuclear-reactors-february-2026",children:"energy.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["DOE also published a HALEU allocation process in August 2025 that explicitly tied the release of at least 20 metric tons of HALEU to EO 14299. That is another direct linkage. The order did not merely proclaim a future fuel supply. It pushed DOE to operationalize federal control over a scarce and strategically important fuel form for private projects. (",(0,n.jsx)(t.a,{href:"https://www.energy.gov/sites/default/files/2025-08/HALEU%20Allocation%20Process%2008282025%20%28Final%29_0.pdf",children:"energy.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["There are plausible, though less direct, downstream effects in export finance. EO 14299 ordered a whole-of-government export push using EXIM, DFC, USTDA, and multilateral development banks. By January 29, 2026, EXIM signed a credit agreement supporting Poland\u2019s first nuclear power plant with American technology and expertise. That agreement is not proof that EO 14299 caused the deal by itself, but it is plainly aligned with the order\u2019s export-finance strategy and should be understood as part of the same operating pattern. (",(0,n.jsx)(t.a,{href:"https://www.federalregister.gov/documents/full_text/html/2025/05/29/2025-09796.html",children:"federalregister.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["The broader-pattern context is even more revealing. Before EO 14299 was issued, DIU\u2019s Advanced Nuclear Power for Installations program had already selected eight companies eligible for OT awards and had said it would use NRC civil regulatory pathways. After EO 14299, the Army\u2019s Janus materials emphasized the Army\u2019s own regulatory authorities instead. That shift from an NRC-centered civil pathway to an Army-centered military pathway is not trivial. It is a move away from independent civilian oversight and toward executive-branch self-regulation under a national-security banner. (",(0,n.jsx)(t.a,{href:"https://www.diu.mil/latest/DOD-selects-eligible-companies-for-the-Advanced-Nuclear-Power-for-Installations-Program",children:"diu.mil"}),")"]}),"\n",(0,n.jsx)(t.h2,{id:"who-benefits-and-who-pays",children:"Who Benefits and Who Pays"}),"\n",(0,n.jsxs)(t.p,{children:["The winners are not hard to identify. Reactor developers, fuel-cycle firms, AI infrastructure developers, data-center operators, federal-site contractors, export-oriented nuclear vendors, and agencies seeking to expand their operational turf all stand to gain. DOE\u2019s solicitations explicitly offer long-term leasing opportunities on federal sites for privately funded projects, while the order itself opens access to federal fuel inventories, federal technical support, federal diplomatic advocacy, and potentially federal export financing. In plain English, the administration is using public property and public authority to improve the business case for politically favored industries. (",(0,n.jsx)(t.a,{href:"https://www.energy.gov/ne/articles/energy-department-seeks-proposals-ai-data-centers-energy-projects-idaho-national?utm_source=openai",children:"energy.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["The costs fall on a wider and weaker set of actors. Communities around Oak Ridge, Paducah, Savannah River, and Idaho bear land-use, safety, waste, water, infrastructure, and emergency-planning risks. Those are not pristine greenfield sites. Oak Ridge cleanup still involves contaminated soils and groundwater, including mercury contamination at Y-12; Paducah remains a cleanup and waste-management site that was placed on the Superfund National Priorities List in 1994; Savannah River is still managing tens of millions of gallons of legacy radioactive waste in underground tanks; and Idaho\u2019s cleanup mission still includes spent nuclear fuel and high-level radioactive waste. These communities are being asked to absorb new private-industrial buildout on top of old nuclear burdens. (",(0,n.jsx)(t.a,{href:"https://www.energy.gov/orem/cleanup-sites?utm_source=openai",children:"energy.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["The other major loser is the idea that public safety review should be meaningfully independent of the political branches and of the industries seeking approval. The NRC exists because Congress concluded that promotion and regulation of nuclear technology should not be fused in the same hands. EO 14299, especially when read alongside the NRC \u201creform\u201d order and the administration\u2019s later removal of Commissioner Christopher Hanson without cause, points in the opposite direction: centralize control, subordinate oversight, and make approval speed a political deliverable. That is a classic power-consolidation move, and it is dangerous precisely because nuclear regulation is one of the few areas where delay can be a public good. (",(0,n.jsx)(t.a,{href:"https://www.nrc.gov/about-nrc/governing-laws.html?utm_source=openai",children:"nrc.gov"}),")"]}),"\n",(0,n.jsx)(t.h2,{id:"who-the-administration-is-trying-to-hurt",children:"Who the Administration Is Trying to Hurt"}),"\n",(0,n.jsxs)(t.p,{children:["The administration is trying to hurt anyone positioned to impose friction on its preferred buildout. That includes the NRC when it acts like an independent regulator instead of an industrial partner, CEQ and NEPA when they require real environmental analysis, tribes and nearby residents when they demand consultation or mitigation, and lawmakers who insist that public resources should not be redirected by executive branding exercises dressed up as emergency necessity. The order does not merely favor one side in a policy debate. It is designed to disarm the veto points that make democratic governance slower, more visible, and more accountable. (",(0,n.jsx)(t.a,{href:"https://www.federalregister.gov/documents/full_text/html/2025/05/29/2025-09796.html",children:"federalregister.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["It is also aimed, more specifically, at constituencies that do not produce political glamour or donor excitement. A national laboratory cleanup community does not have the market power of a major AI firm. A tribe asking about cultural resources does not carry the same weight in this administration\u2019s rhetoric as a contractor promising \u201cdominance.\u201d A public-interest safety objection does not fit the administration\u2019s preferred story about heroic speed and decadent regulation. In that sense, the order is a redistribution upward and outward, away from communities living with federal nuclear legacies and toward companies able to monetize federal urgency. (",(0,n.jsx)(t.a,{href:"https://www.energy.gov/sites/default/files/2025-04/RFI%20to%20Inform%20Public%20Bids%20to%20Construct%20AI%20Infrastructure%20%28website%20copy%29%20-%202025.04.10.pdf",children:"energy.gov"}),")"]}),"\n",(0,n.jsx)(t.h2,{id:"legal-authority-constitutional-stakes-and-litigation-exposure",children:"Legal Authority, Constitutional Stakes, and Litigation Exposure"}),"\n",(0,n.jsxs)(t.p,{children:["There is a real statutory basis for some of what the order tries to do. The Atomic Energy Act is the foundational law for both military and civilian nuclear uses, and DOE\u2019s HALEU allocation document cites statutory authorities for DOE distribution of special nuclear material and the HALEU Availability Program. Congress also left defense nuclear facilities outside NRC regulation, creating space for DOE and the military to regulate certain defense-related activities internally. That means the order is not lawless in the simple sense of being written on a blank page. (",(0,n.jsx)(t.a,{href:"https://www.nrc.gov/about-nrc/governing-laws.html?utm_source=openai",children:"nrc.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["But that does not make the order legally secure. Its most vulnerable moves are the ones that stretch defense or research authorities into de facto commercial deployment channels. DOE-site reactors intended to power AI infrastructure or other private industrial loads may not fit comfortably within a theory that these are merely internal government or purely defense facilities. The more a project looks like a privately beneficial commercial reactor using public land and public fuel, the stronger the argument that ordinary civilian regulatory and environmental requirements should attach. That is not settled in the order\u2019s favor; it is precisely where litigation risk lives. (",(0,n.jsx)(t.a,{href:"https://www.whitehouse.gov/presidential-actions/2025/05/deploying-advanced-nuclear-reactor-technologies-for-national-security/",children:"whitehouse.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["The NEPA flank is especially exposed. EO 14299 told Defense and Energy to look for categorical exclusions and emergency pathways, and DOE later created a new advanced-reactor categorical exclusion. DOE insists it will still examine integral elements and extraordinary circumstances, but courts do not simply defer to an agency\u2019s desire for speed when the category is broad, the site conditions are unusual, or the environmental record is thin. A contaminated cleanup site, a reactor paired with a large data center, or a project with significant waste, water, or emergency-planning implications would invite challenges that DOE is misusing categorical treatment. (",(0,n.jsx)(t.a,{href:"https://www.federalregister.gov/documents/full_text/html/2025/05/29/2025-09796.html",children:"federalregister.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["The constitutional stakes are broader than the order\u2019s text. Congress created the NRC as an independent agency, and the NRC describes itself as such. The administration\u2019s companion NRC order demanded reorganization with a DOGE team and a wholesale regulatory rewrite, while AP reported that Trump later fired NRC Commissioner Christopher Hanson without cause. That combination matters because it shows the order is part of a larger project to subordinate independent expertise to presidential command. Whether courts ultimately bless that trend in full is uncertain, but the direction is unmistakable: more presidential control over bodies Congress designed to resist exactly this kind of political pressure. (",(0,n.jsx)(t.a,{href:"https://www.nrc.gov/about-nrc?utm_source=openai",children:"nrc.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["Durability is mixed. As an executive order, EO 14299 can be revoked or narrowed by a subsequent president. But implementation decisions made under it can harden. Once DOE selects sites, signs leases, allocates fuel, issues categorical exclusion determinations, or once the Army uses OT agreements to move designs toward construction, reversal becomes more expensive and legally messier. So the order is formally fragile but operationally sticky. That is why early implementation matters so much: the administration is racing to create facts on the ground before political control changes. (",(0,n.jsx)(t.a,{href:"https://www.energy.gov/ne/articles/energy-department-seeks-proposals-ai-data-centers-energy-projects-idaho-national?utm_source=openai",children:"energy.gov"}),")"]}),"\n",(0,n.jsx)(t.h2,{id:"implementation-feasibility-and-agency-capacity",children:"Implementation Feasibility and Agency Capacity"}),"\n",(0,n.jsxs)(t.p,{children:["The deadlines in EO 14299 are politically theatrical and administratively punishing. Getting an Army-regulated reactor operating at a domestic base by September 30, 2028 requires design selection, vendor contracting, siting, site-specific safety analysis, community engagement, fuel assurance, security planning, interconnection, construction, operator training, waste handling, and emergency preparation. Yet as of November 18, 2025 the Janus Program had only selected nine candidate installations and released an Area of Interest to gather industry concepts. That is not a mature construction program. It is a still-forming acquisition pipeline. (",(0,n.jsx)(t.a,{href:"https://www.federalregister.gov/documents/full_text/html/2025/05/29/2025-09796.html",children:"federalregister.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["DOE\u2019s 30-month target for first operation at a DOE site is similarly aggressive. DOE did move quickly on land selection and solicitations, but the solicitations themselves show that applicants remain responsible for financing, building, operating, decommissioning, interconnection, and satisfying regulatory and permitting requirements. DOE\u2019s own AI infrastructure RFI also flagged long lead times on power equipment, supply-chain constraints, water use, noise, community impacts, and the need to identify environmental sensitivities and land-use conflicts. Inference is unavoidable here: the administration can accelerate paperwork far faster than it can safely compress physical reality. (",(0,n.jsx)(t.a,{href:"https://www.energy.gov/ne/articles/energy-department-seeks-proposals-ai-data-centers-energy-projects-idaho-national?utm_source=openai",children:"energy.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["Fuel supply is another choke point. DOE\u2019s HALEU allocation process states that many advanced reactor designs require HALEU and ties the 20-metric-ton release directly to EO 14299. But scarce fuel is not the same thing as usable fuel delivered on the right schedule, in the right form, with the right fabrication capacity and transport chain. The order tries to solve that with command language, but command language does not build a fuel cycle overnight. (",(0,n.jsx)(t.a,{href:"https://www.energy.gov/sites/default/files/2025-08/HALEU%20Allocation%20Process%2008282025%20%28Final%29_0.pdf",children:"energy.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["Agency capacity is also being strained by the administration\u2019s own choices. DOE\u2019s FY 2026 Nuclear Energy request planned a reduced staffing level of 251.8 as part of reorganization efforts and administration priorities. In the same budget set, DOE requested no funding for the Advanced Small Modular Reactor RD&D subprogram and cut Advanced Reactor Technologies from $73.8 million in FY 2025 enacted to $55 million in FY 2026 requested, while total Reactor Concepts R&D and Demonstration fell 22 percent. At the NRC, the FY 2026 budget request rose modestly, largely to support advanced reactor and export activity, but the agency was simultaneously ordered to reorganize with DOGE involvement and undertake a sweeping regulatory rewrite. This is not a coherent state-capacity strategy. It is a demand for maximal speed under conditions of institutional disruption. (",(0,n.jsx)(t.a,{href:"https://www.energy.gov/sites/default/files/2025-06/doe-fy-2026-vol-4-ne.pdf",children:"energy.gov"}),")"]}),"\n",(0,n.jsx)(t.h2,{id:"fiscal-and-economic-effects",children:"Fiscal and Economic Effects"}),"\n",(0,n.jsxs)(t.p,{children:["EO 14299 is structured to hide public costs behind \u201cprivate funding.\u201d DOE\u2019s Idaho and Oak Ridge solicitations emphasize that applicants would solely fund the infrastructure projects. That framing is politically convenient but economically misleading. The federal government is still contributing the land platform, access to federal research environments, regulatory acceleration, fuel inventories, security processing, staff time, permitting support, and diplomatic/export-finance muscle. Those are real subsidies even when they do not appear as a straightforward construction appropriation. (",(0,n.jsx)(t.a,{href:"https://www.energy.gov/ne/articles/energy-department-seeks-proposals-ai-data-centers-energy-projects-idaho-national?utm_source=openai",children:"energy.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["The direct federal resource transfer most clearly identified in the order is the requirement that DOE release at least 20 metric tons of HALEU for qualifying private projects at DOE sites. DOE\u2019s allocation process describes that release as part of the administration\u2019s effort to transform the nuclear sector. Scarce HALEU is a strategic asset, and directing it toward favored private projects has opportunity costs for other reactor developers, for public R&D priorities, and for any more measured fuel-allocation strategy Congress might have preferred. (",(0,n.jsx)(t.a,{href:"https://www.federalregister.gov/documents/full_text/html/2025/05/29/2025-09796.html",children:"federalregister.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["The budget context is contradictory in ways that should alarm anyone who cares about competent governance. DOE\u2019s FY 2026 request cut several reactor-development lines and planned workforce reductions even as the White House demanded faster deployment. At the same time, broader energy-and-water budget activity included expanded support for advanced nuclear deployment and, through budget reconciliation described by CRS, a $1.0 billion appropriation to cover subsidy costs for the expanded Section 1706 Energy Infrastructure Reinvestment loan program, after rescissions elsewhere in DOE financing authorities. The administration is therefore not pursuing a simple \u201csmaller government\u201d model. It is reallocating state support toward politically preferred industrial channels while stripping or shrinking other public-energy tools. (",(0,n.jsx)(t.a,{href:"https://www.energy.gov/sites/default/files/2025-06/doe-fy-2026-vol-4-ne.pdf",children:"energy.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["Economically, the order is a bet that AI load growth and national-security rhetoric can make advanced nuclear commercially bankable sooner than markets, supply chains, or communities would otherwise allow. AP reported in May 2025 that the nuclear order package came amid surging electricity demand from AI and data centers and that experts viewed the broader goal of quadrupling nuclear production by 2050 as highly unlikely. That matters because the order\u2019s economic logic depends on heroic assumptions: that the demand is durable, the reactors will arrive on time, costs will not spiral, and public opposition can be neutralized without imposing later legal or cleanup liabilities. Those are not safe assumptions. They are venture-capital assumptions wrapped in executive force. (",(0,n.jsx)(t.a,{href:"https://apnews.com/article/e7394fe688d2132a73f67f59bdbe792a?utm_source=openai",children:"apnews.com"}),")"]}),"\n",(0,n.jsx)(t.h2,{id:"institutional-regulatory-and-societal-harms",children:"Institutional, Regulatory, and Societal Harms"}),"\n",(0,n.jsxs)(t.p,{children:["The first harm is degradation of oversight culture. When an order tells agencies to find categorical exclusions, emergency pathways, new exclusions, and alternative arrangements under NEPA, the message to staff is unmistakable: scrutiny is a hurdle, not a duty. When a companion order tells the NRC to reorganize with DOGE, weigh the economic and national-security \u201cbenefits\u201d of nuclear power alongside safety, and create expedited pathways for DOE- or DOD-tested designs, the same message gets louder. Oversight becomes something to be engineered around. (",(0,n.jsx)(t.a,{href:"https://www.federalregister.gov/documents/full_text/html/2025/05/29/2025-09796.html",children:"federalregister.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["The second harm is burden shifting onto already burdened places. Oak Ridge, Paducah, Savannah River, and Idaho are not abstract coordinates. They are places with long nuclear histories, active cleanup missions, contaminated soils or groundwater, radioactive waste legacies, and ongoing public-health and stewardship obligations. Adding AI-centered private development and new reactor deployment to those sites risks crowding cleanup, complicating stewardship, and normalizing the idea that communities that already carried the Cold War can be conscripted again for the next techno-industrial rush. That is not just inefficient. It is unjust. (",(0,n.jsx)(t.a,{href:"https://www.energy.gov/orem/cleanup-sites?utm_source=openai",children:"energy.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["The third harm is democratic. DOE\u2019s AI infrastructure RFI openly acknowledged the need to hear from tribes and communities about adverse impacts, cultural resources, energy prices, noise, water use, and land footprint. But EO 14299\u2019s implementation path, especially once combined with categorical exclusions and \u201ccritical defense\u201d designations, is designed to reduce the practical power of those communities to shape outcomes. Consultation without leverage is not accountability. It is extraction with a public-comment veneer. (",(0,n.jsx)(t.a,{href:"https://www.energy.gov/sites/default/files/2025-04/RFI%20to%20Inform%20Public%20Bids%20to%20Construct%20AI%20Infrastructure%20%28website%20copy%29%20-%202025.04.10.pdf",children:"energy.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["The fourth harm is nonproliferation and export-governance risk. The order\u2019s demand for at least 20 new 123 agreements by the end of the 120th Congress, aggressive renegotiations, and 30-day export authorization decisions pushes diplomatic and technical processes toward throughput. The order says implementation must respect nonproliferation obligations, but compressed timelines and politically charged export targets can still degrade judgment, especially when success is being measured in deal count and market share. (",(0,n.jsx)(t.a,{href:"https://www.federalregister.gov/documents/full_text/html/2025/05/29/2025-09796.html",children:"federalregister.gov"}),")"]}),"\n",(0,n.jsx)(t.h2,{id:"corruption-patronage-and-self-dealing-risk",children:"Corruption, Patronage, and Self-Dealing Risk"}),"\n",(0,n.jsxs)(t.p,{children:["There is no direct public evidence in the sources reviewed that EO 14299 has already been used for bribery, embezzlement, or personal enrichment. That said, the order creates exactly the kind of architecture in which corruption can flourish. It authorizes use of \u201cany useful contract or agreement,\u201d routes work through OT and CSO mechanisms on the military side, opens federal sites to long-term private leasing on the DOE side, allocates scarce fuel, elevates favored projects with national-security labels, and compresses environmental and regulatory review. Those are not proof of corruption. They are corruption opportunities. (",(0,n.jsx)(t.a,{href:"https://www.federalregister.gov/documents/full_text/html/2025/05/29/2025-09796.html",children:"federalregister.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["The ugliest but realistic scenario is not a cartoonish suitcase of cash. It is politically connected favoritism disguised as urgent industrial policy. A company with ties to senior officials, donors, or family networks could receive preferential access to federal land, fuel, or accelerated approvals. A vendor could be steered into an OT agreement or lease structure with weak competition and limited public disclosure. A foreign partner seeking export approval or EXIM support could be told, implicitly or explicitly, that political loyalty, downstream business for insiders, or jobs for relatives would smooth the path. An administration willing to label private infrastructure \u201ccritical defense\u201d has already created a rhetorical shield that can be used to resist scrutiny. (",(0,n.jsx)(t.a,{href:"https://www.whitehouse.gov/presidential-actions/2025/05/deploying-advanced-nuclear-reactor-technologies-for-national-security/",children:"whitehouse.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["There is also a more political form of corruption built into the order\u2019s design. By shifting projects onto military installations and sensitive DOE sites, the administration increases its ability to reward supportive localities, punish hostile ones, and claim patriotic necessity whenever critics object. Hurting political opponents for points, starving certain communities of procedural recourse while fast-tracking others, and using national-security branding to privilege friendly contractors are all forms of corrupt governance even when the exchange is influence rather than cash. The order is ripe for that abuse because it concentrates discretion and narrows oversight at the same time. (",(0,n.jsx)(t.a,{href:"https://www.army.mil/article-amp/289074/army_announces_next_steps_on_janus_program_for_next_generation_nuclear_energy",children:"army.mil"}),")"]}),"\n",(0,n.jsx)(t.h2,{id:"how-a-later-administration-could-reverse-mitigate-or-reform-it",children:"How a Later Administration Could Reverse, Mitigate, or Reform It"}),"\n",(0,n.jsxs)(t.p,{children:["A subsequent administration could revoke EO 14299 outright, but simple revocation would not be enough. It would need to suspend or revisit site-specific implementation decisions, withdraw or narrow \u201ccritical defense\u201d designations for AI data centers, pause further HALEU allocations tied to private AI-serving reactors, and direct DOE and DoD to restore full environmental review where projects do not clearly qualify for narrow exclusions. It should also revisit the February 2, 2026 categorical exclusion for advanced reactors and either rescind it or cabin it sharply so that reactors at legacy cleanup sites or in mixed public-private developments receive full environmental assessment or impact statement review. (",(0,n.jsx)(t.a,{href:"https://www.whitehouse.gov/presidential-actions/2025/05/deploying-advanced-nuclear-reactor-technologies-for-national-security/",children:"whitehouse.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["Structural reform would require more than executive housekeeping. Congress could clarify that reactors primarily serving private commercial loads at DOE sites cannot evade ordinary civilian regulatory requirements by piggybacking on federal land control; tighten conflict-of-interest and competition rules for OT and lease-based deployment models; require transparent public-interest findings before DOE land or fuel inventories are committed to private data-center projects; and reaffirm NRC independence, including protection against at-will removal of commissioners. A serious reform agenda would also protect tribal consultation, require host-community benefit agreements, and bar the use of emergency NEPA arrangements absent a genuine, documentable emergency rather than a politically declared race for AI capacity. (",(0,n.jsx)(t.a,{href:"https://www.nrc.gov/about-nrc?utm_source=openai",children:"nrc.gov"}),")"]}),"\n",(0,n.jsx)(t.h2,{id:"conclusion",children:"Conclusion"}),"\n",(0,n.jsxs)(t.p,{children:["EO 14299 is a bad-faith instrument of executive power. Its official text talks about security, resilience, and leadership, but its operating logic is to funnel public assets and public-law advantages toward a narrow set of private and bureaucratic winners while cutting down the oversight structures that might force the administration to justify itself honestly. The order does not merely seek more nuclear energy. It seeks a different constitutional and administrative balance, one in which national-security branding can convert contested private infrastructure into favored federal priority, independent regulation can be bent toward promotion, and communities already living with nuclear legacies can be told to carry more risk so that politically connected industries can move faster. (",(0,n.jsx)(t.a,{href:"https://www.federalregister.gov/documents/full_text/html/2025/05/29/2025-09796.html",children:"federalregister.gov"}),")"]}),"\n",(0,n.jsxs)(t.p,{children:["That is why the right response is not to admire the order\u2019s speed or repeat its framing. The right response is to name what it is doing. It is expanding executive authority, weakening oversight, redistributing scarce public resources upward, altering enforcement priorities in favor of speed and industry access, and eroding democratic safeguards in exactly the places where caution and accountability are most necessary. The administration is trying to hurt oversight, hurt dissent, and hurt the people least able to force their way into the room where these deals are being made. The fact that some of its mechanisms rest on real statutory authorities does not redeem the project. It makes the project more urgent to stop. (",(0,n.jsx)(t.a,{href:"https://www.nrc.gov/about-nrc/governing-laws.html?utm_source=openai",children:"nrc.gov"}),")"]})]})}function h(e={}){const{wrapper:t}={...(0,i.R)(),...e.components};return t?(0,n.jsx)(t,{...e,children:(0,n.jsx)(d,{...e})}):d(e)}}}]);